select follow_id, user_id, type, object_id, create_time
from mw_follow
where user_id = #{userId}
  and type = #{type}
  and object_id = #{objectId} limit 1

select follow_id, user_id, type, object_id, create_time
from mw_follow
where user_id = #{userId}
  and type = #{type}
order by follow_id desc

select follow_id, user_id, type, object_id, create_time
from mw_follow
where object_id = #{objectId}
  and type = #{type}
order by follow_id desc

